hooks.body:
try {
      const { message } = JSON.parse(input.body);
      const result = await this.coordinator.invoke({ message });
      input.respond(200, JSON.stringify({ result }));
    } catch (err: any) {
      input.respond(500, JSON.stringify({ error: err.message }));
    }

tools.body:
const result = `Research findings on: ${input.topic}`;
    await this.memory.store({ text: result });
    return result;
